INSERT INTO public.photos VALUES (21100, 'Puente de Piedra 1880', 'Asâ”śÂˇ lucâ”śÂˇa el Puente de Piedra en una guâ”śÂˇa de viaje inglesa de 1880 titulada "Spanish pictures drawn with pen and pencil", si bien era una copia, con sus licencias y modificaciones, del dibujo que Eduard Hanke Locker habâ”śÂˇa realizado en 1813. Para los editores de la obra, ilustrar con imâ”śĂ­genes de hacâ”śÂˇa 67 aâ”śâ–’os una obra actual, era normal. Como con la literatura oral, una copia de una copia puede acabar modificando bastante la realidad que pretende capturar. Las fuentes orales, y los dibujos, son asâ”śÂˇ.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15951919945.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15951919945.webp', 'https://www.flickr.com/photos/zaragozaantigua/15951919945/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21160, 'Puente de Piedra 1890', '"Saragossa", â”śâ”‚leo sobre lienzo, Frank Brangwyn, 1890. Puente de Piedra de Zaragoza; al fondo, la Lonja y el Pilar. Fuente: www.bridgemanimages.com/', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20279883514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20279883514.webp', 'https://www.flickr.com/photos/zaragozaantigua/20279883514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21223, 'El puente de Piedra c.1906', '"Puente de Piedra", Anâ”śâ”‚nimo, Ca.1906. Imagen del puente de Piedra capturado desde el Arrabal, con interesantes aspectos: a la Lonja siguen adosadas las antiguas "Casas de la Puente", luego "Casas Consistoriales", o Ayuntamiento, en estado casi terminal (el edificio, no la instituciâ”śâ”‚n) unos aâ”śâ–’os antes de trasladarse de ubicaciâ”śâ”‚n a la plaza de la Libertad, y ser derribadas estas viejas construcciones. A su lado, el palacio de los Marqueses de Ayerbe. La segunda torre del Pilar, en proceso de ser construida desde 1903, diseâ”śâ–’ada por Josâ”śÂ® de Yarza y Ricardo Magdalena, y decorada con relieves de Dionisio Lasuâ”śÂ®n. Por el puente traquetea un electrificado tranvâ”śÂˇa, aâ”śâ•‘n en vâ”śÂˇa â”śâ•‘nica, de la Lâ”śÂˇnea del Arrabal. Fuente visual: Francisco Marâ”śÂˇn Bagâ”śâ•ťâ”śÂ®s: su tiempo y su ciudad.', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16102519604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16102519604.webp', 'https://www.flickr.com/photos/zaragozaantigua/16102519604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21243, 'Puente de Piedra c.1900', 'Vista del Puente de Piedra de Zaragoza desde el paseo del Ebro. Al fondo, el Cuartel de San Lâ”śĂ­zaro.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65723200, -0.87536700, '0101000020E61000009AEC9FA70103ECBF3DF19C2D20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20089723001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20089723001.webp', 'https://www.flickr.com/photos/zaragozaantigua/20089723001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21253, 'Puente de Piedra 1903', 'La "Perfumerie Xerol" encargâ”śâ”‚ a "La Grande Imprimerie forâ”śÂ®zienne" de Paul-Emile Roustan, de Ruâ”śĂ­n, una colecciâ”śâ”‚n de postales para promocionar la marca. Roustan fue otro de los franceses pioneros de la fotografâ”śÂˇa, mâ”śĂ­s centrado en la publicidad comercial. Asâ”śÂˇ, realizâ”śâ”‚ una serie sobre "Espagne" que incluyâ”śâ”‚ esta convencional imagen del Puente de Piedra y el templo del Pilar desde la margen izquierda, junto al cuartel de San Lâ”śĂ­zaro, interesante por ser realizada antes de que se construyera el gran murallâ”śâ”‚n en piedra como protecciâ”śâ”‚n frente al Ebro. Lo que aquâ”śÂˇ aparece es el previo terraplâ”śÂ®n o escombrera. Al otro lado del Ebro, vista de la ciudad, con detalle de la veterana Casa Consistorial en las traseras de la Lonja.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20470946300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20470946300.webp', 'https://www.flickr.com/photos/zaragozaantigua/20470946300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21303, 'Puente de Piedra c.1900', 'Imagen del puente de Piedra editada con fines comerciales, con su aspecto integral de orilla a orilla, capturada desde el puente de Hierro. A la izquierda, la margen derecha, con algunos restos del antiguo puente de Tablas, en primer plano. A la derecha, la margen izquierda, con el arranque edilicio de la calle de Sobrarbe. Fuente visual: fototipia Hauser y Menet, AMZ.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33790629975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33790629975.webp', 'https://www.flickr.com/photos/zaragozaantigua/33790629975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21325, 'Ebro y Pilar 1903', 'Imagen capturada desde cierta altura junto al cuartel de San Lâ”śĂ­zaro ubicado donde el antiguo convento mercedario, con una vista panorâ”śĂ­mica coloreada en tono mayormente gris que comprende el Puente de Piedra, el râ”śÂˇo Ebro y la fachada ribereâ”śâ–’a de la margen derecha desde la Casa Consisiorial y su anexo en La Lonja (a la izquierda), hasta la iglesia parroquial de San Juan de los Panetes (a la derecha). En el centro de la escena, el palacio de los marqueses de Ayerbe, el Colegio de los Infantes y el templo del Pilar con su antigua torre de Santiago o del suroeste, recrecida una dâ”śÂ®cada antes. Junto al arranque de la torre de Nuestra Seâ”śâ–’ora del Pilar, recrecida poco despuâ”śÂ®s, una vista insâ”śâ”‚lita de la câ”śâ•‘pula de la iglesia del antiguo convento de San Ildefonso. La fluida circulaciâ”śâ”‚n rodada por el Puente de Piedra, en este caso no cuenta con la compaâ”śâ–’â”śÂˇa de algâ”śâ•‘n tranvâ”śÂˇa de la lâ”śÂˇnea del Arrabal, ya electrificada, que daba servicio a la margen izquierda.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65766700, -0.87519400, '0101000020E61000003CF9F4D89601ECBF4754A86E2ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49289177631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49289177631.webp', 'https://www.flickr.com/photos/zaragozaantigua/49289177631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21357, 'Puente de Piedra 1900', 'Imagen capturada a espaldas del cuartel de infanterâ”śÂˇa de San Lâ”śĂ­zaro y centrada en el Puente de Piedra con el fondo edilicio de la ciudad desde la Casa Consistorial y la Lonja, a la izquierda, hasta el templo del Pilar.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65745900, -0.87526900, '0101000020E6100000E57B46223402ECBFFEBAD39D27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54784347558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54784347558.webp', 'https://www.flickr.com/photos/zaragozaantigua/54784347558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21428, 'Puente de Piedra c.1918', 'Imagen centrada en el puente de Piedra y el râ”śÂˇo Ebro, con el telâ”śâ”‚n del fondo del templo del Pilar. Sobre el puente transita un tranvâ”śÂˇa de la elâ”śÂ®ctrica serie "Primitivos" (1-20), en servicio en la lâ”śÂˇnea "Gâ”śĂ­llego", regresando desde la terminal de la carretera de Barcelona junto al puente de Santa Isabel. Fuente visual: "Zaragoza. El Pilar y el puente de piedra", postal en www.ebay.es/', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33664321024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33664321024.webp', 'https://www.flickr.com/photos/zaragozaantigua/33664321024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21458, 'Râ”śÂˇo Ebro 1915', 'Imagen capturada desde la altura de la torre oriental o de Nâ”¬Â¬. Sâ”¬Â¬. del Pilar del homâ”śâ”‚nimo templo, y centrada en una vista del tramo del râ”śÂˇo Ebro comprendido entre el puente de Piedra y el puente "de Hierro". En la margen izquierda, el cuartel de San Lâ”śĂ­zaro como fachada ribereâ”śâ–’a del barrio de Jesâ”śâ•‘s, destacando el que fuera antiguo refectorio del convento mercedario que allâ”śÂˇ estuviera enclavado antaâ”śâ–’o. En primer tâ”śÂ®rmino y a la derecha, en la esquina del paseo del Ebro con la calle de Fernando el Catâ”śâ”‚lico, solar donde estuviera la antigua Casa Consistorial, en proceso de derribo adjudicado por 4.250 pesetas a la empresa de doâ”śâ–’a Joaquina Candao, seâ”śâ–’ora viuda de Vicente. Desde 1912 el Ayuntamiento estaba ubicado en el edificio de la antigua Academia Militar sita en la plaza de Santo Domingo, y allâ”śÂˇ seguirâ”śÂˇa por casi medio siglo.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65676900, -0.87577300, '0101000020E6100000AB0837195506ECBF6803B00111D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52142695042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52142695042.webp', 'https://www.flickr.com/photos/zaragozaantigua/52142695042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21459, 'Câ”¬â•‘. de Juslibol 1911', 'Imagen del arranque del camino de Juslibol junto al puente de Piedra y el principio de la calle del Sobrarbe (a la derecha y fuera de plano) y centrada en el "hospital de sangre" del Arrabal establecido por la Comisiâ”śâ”‚n provincial de la Cruz Roja en la farmacia de la viuda de Sâ”śĂ­nchez de Rojas durante la huelga general convocada a principios del otoâ”śâ–’o de ese aâ”śâ–’o, en previsiâ”śâ”‚n de alguna "alteraciâ”śâ”‚n de orden pâ”śâ•‘blico". Custodiado por varias parejas de guardiaciviles, este fue uno de los ocho "hospitales de sangre" habilitados en Zaragoza para la ocasiâ”śâ”‚n. A la izquierda e inmediato, el antiguo Almacâ”śÂ®n de salvados y semillas de Alejandro Chacen, y al fondo, vista parcial del extenso huerto de Juan Guitar, que se extendâ”śÂˇa hasta el principio del camino de Ranillas, donde el lavadero de Agustâ”śÂˇn Alcrudo. En primer tâ”śÂ®rmino, niâ”śâ–’as provenientes de la escuela municipal ubicada en la calle de Pedro Villacampa, antigua del Tejar.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65846900, -0.87470000, '0101000020E61000005AF5B9DA8AFDEBBF043752B648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52180142959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52180142959.webp', 'https://www.flickr.com/photos/zaragozaantigua/52180142959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21461, 'Câ”¬â•‘. de Juslibol 1911', 'Imagen en acusado claroscuro capturada en el arranque del camino de Juslibol junto al puente de Piedra y centrada en un cacheo rutinario realizado por los guardiaciviles allâ”śÂˇ apostados durante la huelga general convocada a principios del otoâ”śâ–’o de ese aâ”śâ–’o, en previsiâ”śâ”‚n de alguna "alteraciâ”śâ”‚n de orden pâ”śâ•‘blico". Custodiaban ademâ”śĂ­s uno de los ocho "hospitales de sangre" habilitados en Zaragoza para la ocasiâ”śâ”‚n por la Comisiâ”śâ”‚n provincial de la Cruz Roja, en este caso el situado en la farmacia de la viuda de Sâ”śĂ­nchez de Rojas, justo a espaldas del fotâ”śâ”‚grafo. Tras la escena de primer tâ”śÂ®rmino, un tranvâ”śÂˇa elâ”śÂ®ctrico de la lâ”śÂˇnea Arrabal, procedente de la plaza de la Constituciâ”śâ”‚n, casi termina de cruzar el puente de Piedra y se encamina a la calle del Sobrarbe. Al fondo y en la margen derecha se destacan las torres de la iglesia de San Nicolâ”śĂ­s de Bari y la parroquial de Santa Marâ”śÂˇa Magdalena, ademâ”śĂ­s de un torreâ”śâ”‚n del palacio Arzobispal y el cimborrio de la Seo.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65846900, -0.87470000, '0101000020E61000005AF5B9DA8AFDEBBF043752B648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52189034602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52189034602.webp', 'https://www.flickr.com/photos/zaragozaantigua/52189034602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21465, 'Arrabal 1911', 'Imagen capturada en el despejado entorno del Arrabal inmediato al puente de Piedra. La valla de madera del fondo oculta el terreno propiedad de la jefatura provincial de Obras Pâ”śâ•‘blicas delimitado entre el puente y el cuartel de infanterâ”śÂˇa, donde desde 1906 se estaba construyendo el pretil o muro de San Lâ”śĂ­zaro. Sobre la valla y a la derecha emerge el cimborrio de La Seo, y en el centro el remate de la torre de Santa Marâ”śÂˇa Magdalena. La imagen recoge algunos cacheos realizados por policâ”śÂˇas encubiertos durante la Huelga General de septiembre de 1911, al objeto de tratar de impedir el trâ”śĂ­nsito de huelguistas y controlar el acceso al puente desde el Arrabal.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65811600, -0.87467900, '0101000020E61000007CEF6FD05EFDEBBFB77C24253DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53454554622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53454554622.webp', 'https://www.flickr.com/photos/zaragozaantigua/53454554622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21470, 'Puente de Piedra 1912', 'Imagen del Puente de Piedra con su aspecto tras la eliminaciâ”śâ”‚n del antiguo pretil de piedra a finales de la dâ”śÂ®cada anterior, sustituido por una lateral y volada plataforma construida en hormigâ”śâ”‚n armado y cerrada con barandilla metâ”śĂ­lica que desde entonces soportaba el paso peatonal dejando asâ”śÂˇ el ancho del puente para trâ”śĂ­nsito rodado. En la margen izquierda destaca el reciâ”śÂ®n terminado pretil de San Lâ”śĂ­zaro, y tras â”śÂ®l destacan las torres de la iglesia parroquial de N.â”¬Â¬ S.â”¬Â¬ de Altabâ”śĂ­s en la calle del Sobrarbe.', 1912, 1912, 1912, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65713800, -0.87545100, '0101000020E61000001004C8D0B103ECBFBC7A15191DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53571283335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53571283335.webp', 'https://www.flickr.com/photos/zaragozaantigua/53571283335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21526, 'Puente de Piedra 1925', 'Imagen estâ”śĂ­ndar, tomada desde el cuartel de San Lâ”śĂ­zaro, del râ”śÂˇo Ebro, el puente de Piedra, y la ribera derecha centrada en la icâ”śâ”‚nica silueta del templo de El Pilar. Fuente visual: Fundaciâ”śâ”‚n Telefâ”śâ”‚nica', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17021424755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17021424755.webp', 'https://www.flickr.com/photos/zaragozaantigua/17021424755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21529, 'Zaragoza 1929', 'Cartel publicitario del Ferrocarril de Canfranc, representando la ciudad de Zaragoza, diseâ”śâ–’ado por â”śĂ«mile Paul Champseix.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65714800, -0.87534800, '0101000020E6100000EACE13CFD902ECBFDF50F86C1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18956040315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18956040315.webp', 'https://www.flickr.com/photos/zaragozaantigua/18956040315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21536, 'Puente de Piedra 1925', 'Imagen del Puente de Piedra capturada desde el Puente de Hierro. Fuente visual: fotografâ”śÂˇa Josâ”śÂ® Ortiz Echagâ”śâ•ťe ("Espaâ”śâ–’a. Pueblos y paisajes", San Sebastiâ”śĂ­n, 1942). Amablemente aportada por Mariano Lacruz Pâ”śÂ®rez.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65715100, -0.87470200, '0101000020E610000087DD770C8FFDEBBF50C422861DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19657727972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19657727972.webp', 'https://www.flickr.com/photos/zaragozaantigua/19657727972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
