INSERT INTO public.photos VALUES (21589, 'Puente de Piedra c.1920', 'Vista lateral del puente de Piedra. Al fondo, el cuartel de San Lâ”śĂ­zaro. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65678300, -0.87547400, '0101000020E61000001BF2CF0CE203ECBFCDC8207711D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803124631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803124631.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803124631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21605, 'Puente de Piedra c.1925', 'Vista del Puente de Piedra sobre el râ”śÂˇo Ebro con el Arrabal al fondo. Fuente: Foto para postal de Comercial Josan. Cesiâ”śâ”‚n de la familia de Josâ”śÂ® Marâ”śÂˇa Sanz Gonzâ”śĂ­lez a Rafael Castillejo. Dataciâ”śâ”‚n y procesado:', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65713600, -0.87543200, '0101000020E610000060E63BF88903ECBF1B834E081DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27404057565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27404057565.webp', 'https://www.flickr.com/photos/zaragozaantigua/27404057565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21623, 'Calle de Sobrarbe c.1923', 'Imagen del arranque de la calle de Sobrarbe desde el puente de Piedra, ubicaciâ”śâ”‚n desde la que se habrâ”śÂˇa capturado la fotografâ”śÂˇa. En el centro, la unidad 15 (serie "Primitivos") de la lâ”śÂˇnea 4, o Arrabal, circula por la vâ”śÂˇa doble de ese tramo de la calle Sobrarbe, embocada hacia la carretera de Huesca. A la derecha, el convento de Altabâ”śĂ­s, y la iglesia parroquial homâ”śâ”‚nima. A la izquierda, pretil sobre el paso del enlace ferroviario con la estaciâ”śâ”‚n del Norte, y antiguas parcelas del Arrabal. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1923, 1923, 1923, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65843100, -0.87462400, '0101000020E6100000997E8978EBFCEBBF17D68D7747D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33844622362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33844622362.webp', 'https://www.flickr.com/photos/zaragozaantigua/33844622362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21650, 'Puente de Piedra, c.1925', 'Arrabalera imagen capturada en la ribera izquierda del râ”śÂˇo Ebro, donde la arboleda de Macanaz arranca desde el Puente de Piedra. Esta pionera zona verde fue plantada a principios del siglo XVIII como escudo natural ante las riadas que asolaban esta zona de la margen fluvial siniestra cada vez que el Ebro se salâ”śÂˇa de madre. Entre los â”śĂ­lamos, improvisado tendedero utilizado por los habitantes de las precarias infraviviendas del entorno fluvial. Al fondo, el cuartel de infanterâ”śÂˇa de san Lâ”śĂ­zaro, con vista del edificio del refectorio o comedor del antiguo convento mercedario reciâ”śÂ®n reconvertido en dependencias cuarteleras.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65808400, -0.87539700, '0101000020E61000004487C0914003ECBFAC02B5183CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51478807037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51478807037.webp', 'https://www.flickr.com/photos/zaragozaantigua/51478807037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21651, 'Arboleda de Macanaz c.1925', 'Imagen capturada en la arboleda de Macanaz, donde un grupo de nâ”śâ”‚madas de procedencia centroeuropea y etnia gitana se habâ”śÂˇa establecido provisionalmente durante su paso por Zaragoza. Uno de ellos abre la puerta al objetivo del fotâ”śâ”‚grafo para mostrarnos el interior de la infravivienda habilitada temporalmente entre los â”śĂ­lamos de la arboleda. Al fondo y a la izquierda, varias personas contemplan el pasar del agua del râ”śÂˇo Ebro en las inmediaciones al puente de Piedra.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65820400, -0.87549400, '0101000020E6100000E2033BFE0B04ECBF560C570740D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51486872160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51486872160.webp', 'https://www.flickr.com/photos/zaragozaantigua/51486872160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21673, 'Regulares y legionarios 1938', 'AHP Huesca. Carlos Skogler. 1938. El ejâ”śÂ®rcito colonial espaâ”śâ–’ol en el Protectorado de Marruecos era, en julio de 1936, por su profesionalidad, dotaciâ”śâ”‚n en armamento y experiencia en acciones de guerra, la fuerza militar mâ”śĂ­s preparada de todo el ejâ”śÂ®rcito de la Repâ”śâ•‘blica. Su alineaciâ”śâ”‚n con los sublevados fue decisiva, primero, para que el fracasado golpe de Estado derivara en una guerra, y luego porque fue la mâ”śĂ­s efectiva fuerza de choque de los nacionalistas hasta 1939. En la imagen, "regulares" (tropas indâ”śÂˇgenas marroquâ”śÂˇes) y "legionarios" (Legiâ”śâ”‚n espaâ”śâ–’ola, o "Tercio de Extranjeros") del ejâ”śÂ®rcito colonial posando no muy relajados en el Puente de Piedra, con el fondo del Pilar. En la imagen se ha colado un tancredo, y un perro, que al parecer no fueron represaliados por ello.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65717000, -0.87536900, '0101000020E6100000C7D45DD90503ECBFC7F484251ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822133559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822133559.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822133559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21709, 'Puente de Piedra 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El tâ”śÂˇtulo (la fuente visual asâ”śÂˇ lo cataloga) no se corresponde en absoluto con la captura, salvo que sâ”śÂˇ es Zaragoza: se trata de una imagen del puente de Piedra que, tomada muy cerca del puente de Hierro, es casi un panorâ”śĂ­mica que abarca desde el inmenso Palacio Arzobispal (izquierda), hasta el antiguo Molino harinero y el cuartel de San Lâ”śĂ­zaro (derecha) Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65715400, -0.87536500, '0101000020E61000006C04E275FD02ECBFC1374D9F1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17166966630.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17166966630.webp', 'https://www.flickr.com/photos/zaragozaantigua/17166966630/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21711, 'Puente de Piedra 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El tâ”śÂˇtulo (la fuente visual asâ”śÂˇ lo cataloga) no se corresponde con la captura, salvo en que sâ”śÂˇ es Zaragoza: se trata de una imagen parcial del puente de Piedra que, tomada desde la margen derecha, un poco por debajo del nivel del paseo de la Ribera, captura el entronque del puente con la ribera izquierda, con visual del muro pâ”śÂ®treo de defensa fluvial de San Lâ”śĂ­zaro, el convento de Santa Isabel, y las torrecillas de la parroquia de Altabâ”śĂ­s. Las viviendas chaflanean alabeadamente la calle Sobrarbe con la trinchera del ferrocarril que conecta la estaciâ”śâ”‚n del Norte con la de Delicias. Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65808700, -0.87458400, '0101000020E61000000C5BB39597FCEBBF1D76DF313CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17354372691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17354372691.webp', 'https://www.flickr.com/photos/zaragozaantigua/17354372691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21764, 'Puente de Piedra 1932', 'Puente de Piedra con detalle del monumento en memoria de Basilio Boggiero, Santiago de Sas y el Barâ”śâ”‚n de Warsage. Al fondo, el Pilar. Fuente visual: Foto Conrado Barlâ”śÂ®s, donada por Daniel Barlâ”śÂ®s y digitalizada por Josâ”śÂ® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22621297024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22621297024.webp', 'https://www.flickr.com/photos/zaragozaantigua/22621297024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21804, 'Vista de Zaragoza 1932', 'Litografâ”śÂˇa de Serge Rovinsky, con el puente de Piedra sobre el Ebro y la Seo y el Pilar al fondo. Fuente: Espagne grandiose et fantastique, Aulard, Parâ”śÂˇs, 1932.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65734300, -0.87523600, '0101000020E6100000F70489EDEE01ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27339675308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27339675308.webp', 'https://www.flickr.com/photos/zaragozaantigua/27339675308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21827, 'Sixto Celorrio 1933', 'Imagen de la esquinera y destacable fachada de la fâ”śĂ­brica "Mosaicos Herrero", empresa reconocida en la â”śÂ®poca por su participaciâ”śâ”‚n edilicia en la nueva estaciâ”śâ”‚n de Las Delicias, el Frontâ”śâ”‚n Aragonâ”śÂ®s, el Frontâ”śâ”‚n Jai Alai, la Academia General Militar, et alia. A la izquierda, el arranque de la calle de Demetrio Galâ”śĂ­n, redenominada Garcâ”śÂˇa Arista tras el 18 de julio de 1936. Hacia la derecha, la calle de Sixto Celorrio. Este edificio no ha perdurado. Fuente visual: diario "El Noticiero". Archivo Josâ”śÂ® Marâ”śÂˇa Ballestâ”śÂˇn Miguel.', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65927200, -0.87577200, '0101000020E6100000941458005306ECBF92955F0663D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32568372816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32568372816.webp', 'https://www.flickr.com/photos/zaragozaantigua/32568372816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21919, 'Calle del Sobrarbe 1939', 'Imagen capturada durante la matinal de Nochevieja del "Aâ”śâ–’o de la Victoria" en el arranque de la calle del Sobrarbe y centrada en la gran cabalgata anunciadora de las fiestas del "XIX Centenario de la venida de la Virgen en carne mortal (sic) a Zaragoza". Compuesta por un heraldo encargado de entregar la Pastoral del Prelado donde se "invitaba a los fieles a participar en las solemnidades del centenario" a todas las parroquias de la ciudad, acompaâ”śâ–’ado por una vistosa comparsa de casi cincuenta figurantes "ricamente vestidos a la usanza imperial", unos a pie y la mayorâ”śÂˇa a caballo. En este caso, la comitiva se dirige a cruzar el puente de Piedra de regreso a la urbe tras entregar la referida Pastoral a la arrabalera parroquia de Nâ”¬Â¬. Sâ”¬Â¬. de Altabâ”śĂ­s. Al fondo, fachada ribereâ”śâ–’a de la margen derecha dominada por la mole del templo del Pilar.', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65834000, -0.87468900, '0101000020E6100000607825C973FDEBBF07D3307C44D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54235617941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54235617941.webp', 'https://www.flickr.com/photos/zaragozaantigua/54235617941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21961, 'Râ”śÂˇo Ebro c.1942', 'Vista del râ”śÂˇo Ebro a su paso por el puente de Piedra de Zaragoza, desde el Pilar, y del barrio de Jesâ”śâ•‘s en la Margen Izquierda, en los aâ”śâ–’os 40. Fuente: rafaelcastillejo.com', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20711963635.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20711963635.webp', 'https://www.flickr.com/photos/zaragozaantigua/20711963635/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21983, 'Baturros 1949', 'Vista del Pilar desde la margen izquierda del râ”śÂˇo Ebro, donde posan unos baturros con burro. Para hacer mâ”śĂ­s tradicional la imagen, un preciso retoque manual ha eliminado, a la izquierda, la nueva Casa Consistorial en obras. Fuente: www.facebook.com/photo.php?fbid=10210611074892567&set...', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65808100, -0.87545300, '0101000020E61000003EEC8502B603ECBF3B8F8AFF3BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28910045645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28910045645.webp', 'https://www.flickr.com/photos/zaragozaantigua/28910045645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22026, 'Puente de Piedra c.1944', 'Imagen capturada en el arranque de la avenida de Cataluâ”śâ–’a y la calle del Sobrarbe y orientada hacia el sur, con el fondo del templo del Pilar, cuando efectivos militares marchan en formaciâ”śâ”‚n sobre el puente de Piedra para dirigirse a realizar maniobras en los Pinares de Venecia. En primer tâ”śÂ®rmino, vâ”śÂˇas de las lâ”śÂˇneas del tranvâ”śÂˇa 4. Arrabal, 9. Gâ”śĂ­llego y 10. Academia', 1944, 1944, 1944, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65829200, -0.87472200, '0101000020E61000004EEFE2FDB8FDEBBFF69B89E942D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50162258261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50162258261.webp', 'https://www.flickr.com/photos/zaragozaantigua/50162258261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22063, 'El Pilar 1956', 'Vuelta ciclista a Espaâ”śâ–’a, mayo de 1956. Paso por el puente de Piedra de los ciclistas participantes en la vuelta de 1956. Al fondo, el Pilar con sus dos torres en obras. Tambiâ”śÂ®n el ayuntamiento, en esqueleto aâ”śâ•‘n. Fuente: elbalcondesanlazaro.blogspot.com.es/2013/12/la-vuelta-cic...', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65798400, -0.87487500, '0101000020E6100000E5D022DBF9FEEBBF48A5D8D138D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15045000974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15045000974.webp', 'https://www.flickr.com/photos/zaragozaantigua/15045000974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22072, 'Puente de Piedra aâ”śâ–’os 50', 'Foto Luis Mompel/Heraldo de Aragâ”śâ”‚n, aâ”śâ–’os 50 del siglo XX. Un grupo de personas intenta levantar un cuadrâ”śâ•‘pedo que parece haberse caâ”śÂˇdo por el sobrepeso del carro que transporta, en el Puente de Piedra de Zaragoza. Al fondo a la derecha, las torres de la iglesia de Nuestra Seâ”śâ–’ora de Altabâ”śĂ­s. Fuente: www.facebook.com/photo.php?fbid=4878857666515&set=o.6...', 1950, 1950, 1959, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65777000, -0.87499600, '0101000020E6100000A52F849CF7FFEBBF1C25AFCE31D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15470899799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15470899799.webp', 'https://www.flickr.com/photos/zaragozaantigua/15470899799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22111, 'Puente de Piedra c.1950', 'Desde el Arrabal y en el edificio de cuatro alturas que daba principio a la calle de Sixto Celorrio, una vista al inmediato punto donde comenzaban la avenida de Cataluâ”śâ–’a y la calle del Sobrarbe, cada una seâ”śâ–’alada por su correspondiente tendido tranviario. Sobre el puente de Piedra transitan peatones, unos pocos vehâ”śÂˇculos y un par de tranvâ”śÂˇas de las cuatro lâ”śÂˇneas que entonces lo cruzaban. Al fondo, la fachada del Casco Viejo al râ”śÂˇo Ebro de la que se destacan las torres de la Magdalena y de la iglesia del Real Seminario de San Carlos Borromeo, el cimborrio y la torre de la Seo, y la torre occidental de la iglesia del Sagrado Corazâ”śâ”‚n de Jesâ”śâ•‘s, en la plaza de San Pedro Nolasco. Al fondo, la plaza de La Seo, la Lonja y el ayuntamiento en construcciâ”śâ”‚n. Fuente visual: www.todocoleccion.net/', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22099641600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22099641600.webp', 'https://www.flickr.com/photos/zaragozaantigua/22099641600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22188, 'Puente de Piedra c.1950', 'Imagen capturada de forma muy creativa desde la altura de las antiguas viviendas que chaflaneaban el arranque de la calle de Sobrarbe, la zanja del enlace ferroviario, y el principio de la calle de Sixto Celorrio, con una interesante visual, en primer tâ”śÂ®rmino, del puente de Piedra y el terraplâ”śÂ®n en descenso hasta el talud ferrovario. Al fondo, la margen derecha, con las destacadas obras de la nueva casa consistorial, y el tâ”śÂˇmido comienzo del recrecimiento de la torre nororiental del Pilar. Fuente visual: www.ebay.es/', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65816600, -0.87496700, '0101000020E6100000128942CBBAFFEBBF69AB92C83ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32172079975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32172079975.webp', 'https://www.flickr.com/photos/zaragozaantigua/32172079975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22372, 'Vista aâ”śÂ®rea Ebro 1964', 'Vista aâ”śÂ®rea de Zaragoza desde el Ebro, pasando bajo el puente de Piedra. Al fondo, el paseo de la Independencia. Fuente: Colecciâ”śâ”‚n Rafael Margalâ”śÂ®.', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21695523153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21695523153.webp', 'https://www.flickr.com/photos/zaragozaantigua/21695523153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
