INSERT INTO public.photos VALUES (22512, 'Puente de Piedra 1964', 'Imagen centrada en el puente de Piedra sobre el râ”śÂˇo Ebro, con peatones cruzando por los laterales voladizos junto a la metâ”śĂ­lica valla con funciâ”śâ”‚n quitamiedos, mientras por la calzada cruza trâ”śĂ­fico, incluso pesado. Sobre el puente, tendido utilizado por los tranvâ”śÂˇas de las lâ”śÂˇneas Arrabal y Academia, los trolebuses de la lâ”śÂˇnea Gâ”śĂ­llego y los que regresaban del barrio de Jesâ”śâ•‘s. Al fondo, panorama de antiguos edificios de vivienda en el arranque de la calle del Sobrarbe y junto al tâ”śâ•‘nel del enlace ferroviario que pasaba por debajo, ademâ”śĂ­s del convento de Altabâ”śĂ­s, tras el que se ve parcialmente la iglesia del mismo nombre. En primer tâ”śÂ®rmino, los potentes tajamares del puente, poblados en su parte superior por vegetaciâ”śâ”‚n que encuentra acomodo casi en cualquier parte.', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65681700, -0.87592300, '0101000020E6100000FE0DDAAB8F07ECBF793A579412D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51089274807.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51089274807.webp', 'https://www.flickr.com/photos/zaragozaantigua/51089274807/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22582, 'Riada Ebro 1978', 'Luis Serrano Pardo. 1978. Imagen, desde el puente de Hierro, de la riada que el mes de febrero de ese aâ”śâ–’o llegâ”śâ”‚ a la ciudad. Desde la gran riada de 1961 el Ebro no habâ”śÂˇa bajado asâ”śÂˇ. Fuente: "El Ebro desbordado. Una historia de las crecidas del râ”śÂˇo en Zaragoza", Ayuntamiento de Zaragoza, 2011.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65715400, -0.87538600, '0101000020E61000004A0A2C802903ECBFC1374D9F1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15591636219.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15591636219.webp', 'https://www.flickr.com/photos/zaragozaantigua/15591636219/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22594, 'Tâ”śâ•‘nel de San Lâ”śĂ­zaro 1970', 'Vista de las vâ”śÂˇas del enlace que conectaba la estaciâ”śâ”‚n del Arrabal con la estaciâ”śâ”‚n de Delicias. Al fondo, tâ”śâ•‘nel de San Lâ”śĂ­zaro bajo la calle del Sobrarbe. El puente de Piedra queda a la izquierda. A la derecha, convento de las Terciarias franciscanas de Altabâ”śĂ­s, por el que sobresale el moderno bloque del nâ”¬â•‘ 2 de la calle de Sixto Celorrio. Tras el desmantelamiento del tendido ferroviario, este tâ”śâ•‘nel fue reutilizado por el trâ”śĂ­fico motorizado.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65822000, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16804954258.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16804954258.webp', 'https://www.flickr.com/photos/zaragozaantigua/16804954258/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22695, 'Baturros y Pilar c.1972', 'Cuadro de jota en el pretil de San Lâ”śĂ­zaro. Detrâ”śĂ­s, el puente de Piedra y el Pilar. Fuente: Foto para postal de Comercial Josan. Cesiâ”śâ”‚n de la familia de Josâ”śÂ® Marâ”śÂˇa Sanz Gonzâ”śĂ­lez a Rafael Castillejo. Dataciâ”śâ”‚n y procesado:', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65800200, -0.87469000, '0101000020E6100000766C04E275FDEBBFEF59D76839D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321088072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321088072.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321088072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
