INSERT INTO public.photos VALUES (22835, 'Puente de Piedra c.1985', 'El puente de Piedra sobre el râ”śÂˇo Ebro, en una imagen que ilustra su papel como importante acceso rodado a la ciudad, antes de su remodelaciâ”śâ”‚n basada en un anteproyecto de 1982 y ejecutada en 1991, con direcciâ”śâ”‚n del arquitecto Josâ”śÂ® Manuel Pâ”śÂ®rez Latorre. Dos carriles de circulaciâ”śâ”‚n rodada, con quitamiedos estilo autovâ”śÂˇa para el trâ”śĂ­nsito de peatones, y seâ”śâ–’alizaciones para ir al sureste, al centro, y al suroeste. Es decir, procediendo desde el norte, a todas partes. La disparatada hegemonâ”śÂˇa del coche, llevada al paroxismo. Aunque la citada restauraciâ”śâ”‚n fue concebida para dejar el paso exclusivo para los peatones, el Ayuntamiento decidiâ”śâ”‚ que tambiâ”śÂ®n podrâ”śÂˇan atravesarlo los autobuses urbanos y los taxis, por lo que fue necesario modificar el pavimento una vez acabada la obra, al no ser el adecuado. Al fondo, el palacio arzobispal, la torre de la Seo, la Lonja y el Ayuntamiento.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65804400, -0.87480200, '0101000020E610000069368FC360FEEBBF1DAA29C93AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14763710599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14763710599.webp', 'https://www.flickr.com/photos/zaragozaantigua/14763710599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22841, 'Arrabal 1985', '1985. Arboleda de Macanaz, puente de Piedra y balcâ”śâ”‚n de San Lâ”śĂ­zaro.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65806100, -0.87461300, '0101000020E61000009F01F566D4FCEBBFF3E2C4573BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14907942943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14907942943.webp', 'https://www.flickr.com/photos/zaragozaantigua/14907942943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22938, 'Puente de Piedra 1983', 'Puente de Piedra sobre el Ebro en su etapa de hegemonâ”śÂˇa vial motorizada, con el fondo de la fachada ribereâ”śâ–’a desde la Lonja, a la derecha, pasando por la Seo, hasta la Magdalena. Se trata de una viâ”śâ–’eta del câ”śâ”‚mic "Buscar a Efe" publicado por entregas en Andalâ”śĂ­n, con guiâ”śâ”‚n de J. A. Labordeta, y dibujo de Isidro Ferrer. Fuente visual: "Andalâ”śĂ­n, periâ”śâ”‚dico quincenal aragonâ”śÂ®s".', 1983, 1983, 1983, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65711600, -0.87552000, '0101000020E610000031CEDF844204ECBFD4D688601CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32632047505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32632047505.webp', 'https://www.flickr.com/photos/zaragozaantigua/32632047505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
